// Normaliza os itens do Apify para o formato BulkImportRequest do CRM
const apifyItems = $input.all();

function extractWhatsApp(phone) {
  if (!phone) return null;
  // Tenta extrair de URLs wa.me/5511...
  const waMatch = phone.match(/wa\.me\/(\d+)/);
  if (waMatch) return '+' + waMatch[1];
  // Limpa o número e assume que é WhatsApp se tiver DDD válido
  const cleaned = phone.replace(/[^0-9+]/g, '');
  if (cleaned.length >= 10) return cleaned.startsWith('+') ? cleaned : '+55' + cleaned.replace(/^0/, '');
  return null;
}

function cleanPhone(phone) {
  if (!phone) return null;
  const cleaned = phone.replace(/[^0-9+]/g, '');
  if (cleaned.length < 8) return null;
  return cleaned.startsWith('+') ? cleaned : '+55' + cleaned.replace(/^0/, '');
}

const customers = apifyItems.map(item => {
  const d = item.json;
  const email = Array.isArray(d.emails) && d.emails.length > 0 ? d.emails[0] : null;
  const phone = cleanPhone(d.phone);
  const whatsApp = extractWhatsApp(d.phone) || phone;

  // Monta tags: cidade + categoria
  const tagParts = [];
  if (d.city) tagParts.push(d.city.toLowerCase().replace(/\s+/g, '-'));
  if (d.categoryName) tagParts.push(d.categoryName.toLowerCase().replace(/\s+/g, '-'));
  if (d.website) tagParts.push('tem-site');
  else tagParts.push('sem-site');
  tagParts.push('google-maps');

  // Monta notes com contexto do lead
  const notesParts = [];
  if (d.address) notesParts.push(`Endereço: ${d.address}`);
  if (d.totalScore) notesParts.push(`Avaliação Google: ${d.totalScore}`);
  if (d.reviewsCount) notesParts.push(`Reviews: ${d.reviewsCount}`);
  if (d.website) notesParts.push(`Site: ${d.website}`);

  return {
    name: d.title || d.name || 'Sem nome',
    email: email,
    phone: phone,
    whatsApp: whatsApp,
    companyName: d.title || d.name || null,
    website: d.website || null,
    tags: tagParts.join(','),
    notes: notesParts.join(' | ') || null
  };
}).filter(c => c.name && c.name !== 'Sem nome' && (c.phone || c.email));

if (customers.length === 0) {
  return [{ json: { skipped: true, reason: 'Nenhum lead válido encontrado no dataset Apify' } }];
}

return [{
  json: {
    customers: customers,
    source: 11
  }
}];

const result = $input.first().json;
console.log(`[Segmentação] Total: ${result.totalProcessed} | HOT: ${result.hotCount} | WARM: ${result.warmCount} | COLD: ${result.coldCount}`);
return [{ json: { success: true, result } }];

const result = $input.first().json;
const campaignId = result.campaignId || 'N/A';
const queued = result.queuedCount ?? 0;
const skipped = result.skippedCount ?? 0;
console.log(`[Envio de Campanha] CampaignId: ${campaignId} | Enfileirados: ${queued} | Pulados: ${skipped}`);
if (result.skippedReasons && result.skippedReasons.length > 0) {
  console.log(`[Envio de Campanha] Motivos pulados: ${result.skippedReasons.join('; ')}`);
}
return [{ json: { success: true, campaignId, queued, skipped, result } }];

const error = $input.first().json;
const workflow = error.workflow?.name || 'Desconhecido';
const node = error.execution?.lastNodeExecuted || 'Desconhecido';
const errorMsg = error.execution?.error?.message || JSON.stringify(error);
const execId = error.execution?.id || 'N/A';

console.error(`[ERRO] Workflow: ${workflow}`);
console.error(`[ERRO] Nó: ${node}`);
console.error(`[ERRO] Execução ID: ${execId}`);
console.error(`[ERRO] Mensagem: ${errorMsg}`);

// Retorna resumo do erro para possível integração futura (ex: Slack, email)
return [{
  json: {
    alertType: 'workflow_error',
    workflow,
    node,
    execId,
    errorMsg,
    timestamp: new Date().toISOString()
  }
}];
